THOUGHT: The crash is due to an insertelement not dominating its shufflevector use: SLP creates a broadcast via shufflevector that uses a vector built from a single scalar using insertelement, but the insertelement can be emitted in a block that does not dominate the shuffle. A robust fix is to hoist insertelement of non-instruction scalars (like function arguments/constants) to a dominating location. In the CreateInsertElement lambda, I will guard the builder insertion point and, when the scalar is not an Instruction, temporarily set the insertion point to the start of the function’s entry block (which dominates all blocks) before emitting the insertelement, then restore the original insertion point. This ensures dominance without affecting cases where the scalar depends on an instruction (handled by existing postponement logic).

```bash
applypatch << 'EOF'
*** Begin Patch
*** Update File: llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
@@
   auto &&CreateInsertElement = [this](Value *Vec, Value *V, unsigned Pos,
                                       Type *Ty) {
     Value *Scalar = V;
     if (Scalar->getType() != Ty) {
       assert(Scalar->getType()->isIntOrIntVectorTy() &&
              Ty->isIntOrIntVectorTy() && "Expected integer types only.");
       Value *V = Scalar;
       if (auto *CI = dyn_cast<CastInst>(Scalar);
           isa_and_nonnull<SExtInst, ZExtInst>(CI)) {
         Value *Op = CI->getOperand(0);
         if (auto *IOp = dyn_cast<Instruction>(Op);
             !IOp || !(isDeleted(IOp) || isVectorized(IOp)))
           V = Op;
       }
       Scalar = Builder.CreateIntCast(
           V, Ty, !isKnownNonNegative(Scalar, SimplifyQuery(*DL)));
     }

     Instruction *InsElt;
     if (auto *VecTy = dyn_cast<FixedVectorType>(Scalar->getType())) {
       assert(SLPReVec && "FixedVectorType is not expected.");
       Vec =
           createInsertVector(Builder, Vec, Scalar, Pos * getNumElements(VecTy));
       auto *II = dyn_cast<IntrinsicInst>(Vec);
       if (!II || II->getIntrinsicID() != Intrinsic::vector_insert)
         return Vec;
       InsElt = II;
     } else {
+      // Hoist creation of insertelement for non-instruction scalars to a
+      // dominating location to ensure it dominates all later uses (e.g., when
+      // used as an operand of a shufflevector emitted in a predecessor block).
+      IRBuilderBase::InsertPointGuard Guard(Builder);
+      if (!isa<Instruction>(Scalar)) {
+        if (BasicBlock *InsertBB = Builder.GetInsertBlock()) {
+          if (Function *F = InsertBB->getParent()) {
+            auto FI = F->getEntryBlock().getFirstInsertionPt();
+            if (FI != F->getEntryBlock().end())
+              Builder.SetInsertPoint(&*FI);
+          }
+        }
+      }
       Vec = Builder.CreateInsertElement(Vec, Scalar, Builder.getInt32(Pos));
       InsElt = dyn_cast<InsertElementInst>(Vec);
       if (!InsElt)
         return Vec;
     }
*** End Patch
EOF
 && submit-patch
```

