from pathlib import Path
import re

p = Path("llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp")
s = p.read_text()

# 1) Remove the previously added pointer hoist block before CreateInsertElement.
# Find 'if (Ty->isPointerTy() && !isa<Instruction>(Scalar)) {' block preceding the InsertElement call and remove it with its InsertPointGuard.
def remove_pointer_hoist(src:str)->str:
    pat = re.compile(r"""
      IRBuilderBase::InsertPointGuard\s+Guard\d?\(Builder\);\s*
      if\s*\(\s*Ty->s*isPointerTy\(\)\s*&&\s*!isa<Instruction>\(Scalar\)\s*\)\s*\{
      .*?
      Builder\.SetInsertPoint\(.*?\);\s*
      .*?
      \}\s*
      """, re.S | re.X)
    return pat.sub("", src, count=1)

s = remove_pointer_hoist(s)

# 2) Inject dominance-safe cloning in ShuffleIRBuilder::createShuffleVector (2-operand).
two_hdr_pat = r'Value \*createShuffleVector\(Value \*V1, Value \*V2, ArrayRef<int> Mask\) \{'
if re.search(two_hdr_pat, s):
    s = re.sub(two_hdr_pat,
               r'''Value *createShuffleVector(Value *V1, Value *V2, ArrayRef<int> Mask) {
      // Ensure operands dominate the insertion point by cloning local insertelement(s)
      // if they are after the IP in the same block or from a non-dominating block.
      Instruction *IP = (Builder.GetInsertBlock() && Builder.GetInsertPoint() != Builder.GetInsertBlock()->end())
                            ? &*Builder.GetInsertPoint() : nullptr;
      auto FixOp = [&](Value *Op) -> Value * {
        if (!IP)
          return Op;
        auto *IE = dyn_cast<InsertElementInst>(Op);
        if (!IE)
          return Op;
        BasicBlock *IEBB = IE->getParent();
        BasicBlock *UseBB = IP->getParent();
        bool SameBBLate = (IEBB == UseBB) && !IE->comesBefore(IP);
        bool CrossBBDontDom = (IEBB != UseBB);
        if (CrossBBDontDom) {
          // If we have DT, ensure dominance; otherwise conservatively fix.
          // DT is available via R.DT in outer class, but not here; conservatively fix.
          CrossBBDontDom = true;
