        if (!SameBBLate && !CrossBBDontDom)
          return Op;
        // Clone minimal insertelement at IP: poison base, same scalar and index.
        auto *IdxC = dyn_cast<Constant>(IE->getOperand(2));
        if (!IdxC)
          return Op;
        IRBuilderBase::InsertPointGuard G(Builder);
        Builder.SetInsertPoint(IP);
        Value *Base = PoisonValue::get(IE->getType());
        return Builder.CreateInsertElement(Base, IE->getOperand(1), IdxC);
      };
      V1 = FixOp(V1);
      V2 = FixOp(V2);''', s, count=1)

# 3) Inject dominance-safe cloning in ShuffleIRBuilder::createShuffleVector (1-operand).
