          bool SameBBLate = (IEBB == UseBB) && !IE->comesBefore(IP);
          bool CrossBBDontDom = (IEBB != UseBB);
          if (CrossBBDontDom)
            CrossBBDontDom = true; // Conservatively fix without DT here.
          if (SameBBLate || CrossBBDontDom)
            if (auto *IdxC = dyn_cast<Constant>(IE->getOperand(2))) {
              IRBuilderBase::InsertPointGuard G(Builder);
              Builder.SetInsertPoint(IP);
              Value *Base = PoisonValue::get(IE->getType());
              V1 = Builder.CreateInsertElement(Base, IE->getOperand(1), IdxC);
