messages.content:
THOUGHT: The crash occurs because a shufflevector is created in a block that is not dominated by an insertelement operand defined in another block. Prior attempts either hoisted insertelement broadly (breaking test ordering) or cloned intra-block (also breaking checks). The minimal fix is to only handle cross-block non-dominance at shuffle emission: if an insertelement operand comes from a different block than the shuffle’s insertion block, clone a minimal insertelement at the start of the use block (after allocas). This ensures dominance without changing intra-block ordering or inserting before allocas, and avoids touching same-block cases that tests are sensitive to.

```bash
python3 - << 'PY'
from pathlib import Path, re

p = Path("llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp")
s = p.read_text()

# Patch two-operand ShuffleIRBuilder::createShuffleVector to clone cross-block IE at use block entry (after allocas).
two_hdr_pat = r'Value \*createShuffleVector\(Value \*V1, Value \*V2, ArrayRef<int> Mask\) \{'
def patch_two(m):
    return m.group(0) + r'''
      // Ensure cross-block dominance only: if an InsertElement operand is defined
      // in a different block than the current insertion block, clone a minimal
      // insertelement at the beginning of the use block (after allocas).
      BasicBlock *UseBB = Builder.GetInsertBlock();
      auto FirstIP = [&]() -> Instruction* {
        if (!UseBB) return nullptr;
        auto FI = UseBB->getFirstInsertionPt();
        if (FI == UseBB->end()) return nullptr;
        // Skip allocas in the entry block.
        if (UseBB == &UseBB->getParent()->getEntryBlock()) {
          auto It = UseBB->begin();
          while (It != UseBB->end() && isa<AllocaInst>(&*It))
            ++It;
          return (It != UseBB->end()) ? &*It : &*FI;
        }
        return &*FI;
      };
      auto FixCrossBlock = [&](Value *Op) -> Value * {
        if (!UseBB) return Op;
        auto *IE = dyn_cast<InsertElementInst>(Op);
        if (!IE) return Op;
        if (IE->getParent() == UseBB) return Op; // same-block handled elsewhere
        auto *IdxC = dyn_cast<Constant>(IE->getOperand(2));
        if (!IdxC) return Op;
        if (Instruction *IP = FirstIP()) {
          IRBuilderBase::InsertPointGuard G(Builder);
          Builder.SetInsertPoint(IP);
          Value *Base = PoisonValue::get(IE->getType());
          return Builder.CreateInsertElement(Base, IE->getOperand(1), IdxC);
        }
        return Op;
      };
      V1 = FixCrossBlock(V1);
      V2 = FixCrossBlock(V2);
      // Ensure intra-block dominance: move same-block insertelement(s) before IP.
      if (Instruction *IP = (Builder.GetInsertBlock() && Builder.GetInsertPoint() != Builder.GetInsertBlock()->end())
                                 ? &*Builder.GetInsertPoint() : nullptr) {
        if (auto *I1 = dyn_cast<InsertElementInst>(V1))
          if (I1->getParent() == IP->getParent() && !I1->comesBefore(IP))
            I1->moveBefore(IP);
        if (auto *I2 = dyn_cast<InsertElementInst>(V2))
          if (I2->getParent() == IP->getParent() && !I2->comesBefore(IP))
            I2->moveBefore(IP);
      }
'''
s, n = re.subn(two_hdr_pat, patch_two, s, count=1)
# Patch one-operand ShuffleIRBuilder::createShuffleVector similarly.
one_hdr_pat = r'Value \*createShuffleVector\(Value \*V1, ArrayRef<int> Mask\) \{'
def patch_one(m):
    return m.group(0) + r'''
      // Ensure cross-block dominance only: clone minimal insertelement at use block entry (after allocas).
      BasicBlock *UseBB = Builder.GetInsertBlock();
