from pathlib import Path
import re

p = Path("llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp")
s = p.read_text()

def inject_moves_two_operand(src: str) -> str:
    # Find two-operand createShuffleVector
    pat = r'(Value \*createShuffleVector\(Value \*V1, Value \*V2, ArrayRef<int> Mask\) \{\s*)'
    m = re.search(pat, src)
    if not m:
        return src
    insert_pos = m.end()
    move_code = r'''
      // Ensure operands dominate the insertion point:
      // 1) Cross-block: if an InsertElement operand is defined in a different block and
      //    has a single use, move it before the current insertion point.
      // 2) Intra-block: if an InsertElement operand appears after the current insertion
      //    point in the same block, move it before the insertion point.
      if (Instruction *IP = (Builder.GetInsertBlock() && Builder.GetInsertPoint() != Builder.GetInsertBlock()->end())
                                 ? &*Builder.GetInsertPoint() : nullptr) {
        auto MoveCross = [&](Value *&Op) {
          if (auto *IE = dyn_cast<InsertElementInst>(Op)) {
            if (IE->getParent() != IP->getParent() && IE->hasOneUse())
              IE->moveBefore(IP);
          }
        };
        MoveCross(V1);
        MoveCross(V2);
        if (auto *I1 = dyn_cast<InsertElementInst>(V1))
          if (I1->getParent() == IP->getParent() && !I1->comesBefore(IP))
            I1->moveBefore(IP);
        if (auto *I2 = dyn_cast<InsertElementInst>(V2))
          if (I2->getParent() == IP->getParent() && !I2->comesBefore(IP))
            I2->moveBefore(IP);
      }
'''
    return src[:insert_pos] + move_code + src[insert_pos:]

