THOUGHT: The crash is due to a shufflevector being emitted before an insertelement operand in the same basic block. Previous attempts that moved/hoisted insertelement broke test ordering. A minimal, safe fix is to adjust only the shuffle’s insertion point: if either operand is an insertelement defined later in the same block, delay the shuffle emission to after the latest such insertelement. This preserves dominance without moving/hoisting other instructions and maintains expected ordering of earlier instructions (like GEPs). I’ll modify both ShuffleIRBuilder::createShuffleVector overloads to compute an adjusted insertion point (after the latest same-block insertelement operand) and set the IRBuilder insertion point there before emitting the shuffle.

```bash
python3 - << 'PY' && submit-patch
from pathlib import Path, re
p = Path("llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp")
s = p.read_text()

def patch_two_operand(s):
    # Find the two-operand createShuffleVector body and inject IP adjustment before creating the shuffle.
    pat = re.compile(r'(Value \*createShuffleVector\(Value \*V1, Value \*V2, ArrayRef<int> Mask\) \{\s*)(.*?)\n\s*Value \*Vec = Builder\.CreateShuffleVector\(V1, V2, Mask\);', re.S)
    def repl(m):
        prefix, body = m.groups()
        adjust = '''
      // Adjust insertion point to ensure insertelement operands dominate the shuffle:
      // if an insertelement operand is later in the same block, move the insertion
      // point after the latest such insertelement.
      if (Builder.GetInsertBlock() && Builder.GetInsertPoint() != Builder.GetInsertBlock()->end()) {
        Instruction *CurIP = &*Builder.GetInsertPoint();
        Instruction *AdjIP = CurIP;
        auto consider = [&](Value *Op) {
          if (auto *IE = dyn_cast<InsertElementInst>(Op))
            if (IE->getParent() == CurIP->getParent() && !IE->comesBefore(AdjIP))
              AdjIP = IE;
        };
        consider(V1);
        consider(V2);
        if (AdjIP != CurIP) {
          if (Instruction *Next = AdjIP->getNextNode())
            Builder.SetInsertPoint(Next);
          else
            Builder.SetInsertPoint(AdjIP->getParent()->getTerminator());
        }
      }
'''
        return prefix + body + adjust + '\n      Value *Vec = Builder.CreateShuffleVector(V1, V2, Mask);'
    return pat.sub(repl, s, count=1)

def patch_one_operand(s):
    # Find the one-operand createShuffleVector body and inject IP adjustment before creating the shuffle.
    pat = re.compile(r'(Value \*createShuffleVector\(Value \*V1, ArrayRef<int> Mask\) \{\s*)(.*?)\n\s*if\s*\(Mask\.empty\)\s*return V1;\s*(.*?)\n\s*Value \*Vec = Builder\.CreateShuffleVector\(V1, Mask\);', re.S)
    def repl(m):
        prefix, pre_mask_body, post_mask_body = m.groups()
        adjust = '''
      // Adjust insertion point to ensure insertelement operand dominates the shuffle:
      // if an insertelement operand is later in the same block, move the insertion
      // point after that insertelement.
      if (Builder.GetInsertBlock() && Builder.GetInsertPoint() != Builder.GetInsertBlock()->end()) {
        Instruction *CurIP = &*Builder.GetInsertPoint();
        if (auto *IE = dyn_cast<InsertElementInst>(V1))
          if (IE->getParent() == CurIP->getParent() && !IE->comesBefore(CurIP)) {
            if (Instruction *Next = IE->getNextNode())
              Builder.SetInsertPoint(Next);
            else
              Builder.SetInsertPoint(IE->getParent()->getTerminator());
          }
      }
'''
        return prefix + pre_mask_body + '\n  if (Mask.empty())\n    return V1;\n' + post_mask_body + adjust + '\n  Value *Vec = Builder.CreateShuffleVector(V1, Mask);'
